CREATE TYPE "ReservationStatus" AS ENUM ('WAITING','BOOKED','ARRIVED','CANCELLED');
CREATE TABLE "Reservation" ("id" TEXT NOT NULL,"contactId" TEXT,"clientName" TEXT NOT NULL,"startsAt" TIMESTAMP(3) NOT NULL,"endsAt" TIMESTAMP(3) NOT NULL,"tableName" TEXT,"location" TEXT NOT NULL DEFAULT 'GSM Guide',"servicePerson" TEXT,"status" "ReservationStatus" NOT NULL DEFAULT 'BOOKED',"notes" TEXT,"recurrenceId" TEXT,"createdBy" TEXT NOT NULL,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "Reservation_pkey" PRIMARY KEY("id"));
CREATE INDEX "Reservation_startsAt_idx" ON "Reservation"("startsAt");CREATE INDEX "Reservation_location_idx" ON "Reservation"("location");CREATE INDEX "Reservation_contactId_idx" ON "Reservation"("contactId");ALTER TABLE "Reservation" ADD CONSTRAINT "Reservation_contactId_fkey" FOREIGN KEY("contactId") REFERENCES "Contact"("id") ON DELETE SET NULL ON UPDATE CASCADE;
